import React, { useContext } from 'react';
import { Link } from 'react-router-dom';
import { SessionContext } from '../context/SessionContext';
import { STAGE_CONFIG, WORKFLOW_STAGES } from '../workflow/stages';

import Card from '../components/common/Card';
import DataTable from '../components/data/DataTable';
import DataToolbar from '../components/data/DataToolbar';
import LoadingSpinner from '../components/common/LoadingSpinner';
import ProblemFormulationCard from '../components/job/ProblemFormulationCard';
import DataReadinessCard from '../components/job/DataReadinessCard';

function DataPreparation() {
  const {
    session, 
    artifacts,
    loading,
    error,
    currentStageConfig
  } = useContext(SessionContext);

  const handleUpload = (file) => { /* Placeholder for future implementation */ };

  const renderContent = () => {
    if (loading) return <LoadingSpinner text="Loading session artifacts..." />;
    if (error) return <p className="text-red-500 text-center p-8">{`Error: ${error.message}`}</p>;
    if (!session) return <p className="text-gray-500 text-center p-8">No active session. Please start one from the dashboard.</p>;

    const { formulation, recommendation } = artifacts;
    const isReadyForNextStep = !!recommendation; // Can proceed once recommendation is available

    return (
      <>
        {/* We can use the artifact summary for readiness once available */}
        {formulation ? (
          <ProblemFormulationCard formulation={formulation} />
        ) : (
          <LoadingSpinner text="Waiting for problem formulation..." />
        )}

        {session.currentStage === WORKFLOW_STAGES.ASSESS_READINESS && !recommendation && (
          <DataReadinessCard readiness={{ status: 'pending', checks: [] }} />
        )}

        {recommendation && (
          <DataReadinessCard readiness={{ status: 'complete', checks: recommendation.readinessChecks }} />
        )}

        <Card>
          <DataToolbar onUpload={handleUpload} datasetName={session?.dataset?.name || 'New Dataset'} />
          <DataTable data={formulation?.data || { columns: [], rows: [] }} />
          <div className="mt-6 text-right">
            <Link 
              to={isReadyForNextStep ? `${STAGE_CONFIG[WORKFLOW_STAGES.PREPARE_SOLVER_INPUT].path}?session=${session.id}` : '#'}
              className={`bg-blue-600 text-white font-bold py-3 px-4 rounded-lg transition duration-300 ${!isReadyForNextStep ? 'opacity-50 cursor-not-allowed' : 'hover:bg-blue-700'}`}
              onClick={(e) => !isReadyForNextStep && e.preventDefault()}
            >
              Proceed to Job Configuration &rarr;
            </Link>
          </div>
        </Card>
      </>
    );
  };

  return (
    <div className="container mx-auto p-8">
      <h1 className="text-3xl font-bold mb-6">Problem Formulation &amp; AI Recommendation</h1>
      <p className="text-lg text-gray-600 mb-6">
        {currentStageConfig?.description || 'Define your problem and let the AI guide recommend the best path forward.'}
      </p>
      {renderContent()}
    </div>
  );
}

export default DataPreparation;
